259	std::vector<common_chat_msg> common_chat_msgs_parse_oaicompat(const json & messages) {
260	    std::vector<common_chat_msg> msgs;
261	
262	    try {
263	        if (!messages.is_array()) {
264	            throw std::invalid_argument("Expected 'messages' to be an array, got " + messages.dump());
265	        }
266	
