1558	// Gemma4 uses a custom tool_responses field instead of role:tool messages.
1559	// Convert consecutive role:tool messages into a single user message with tool_responses.
1560	static void convert_tool_responses_gemma4(json & messages) {
1561	    json result = json::array();
1562	    size_t i = 0;
1563	    while (i < messages.size()) {
1564	        if (messages[i].contains("role") && messages[i].at("role") == "tool") {
1565	            json tool_responses = json::array();
1566	            while (i < messages.size() &&
1567	                   messages[i].contains("role") &&
1568	                   messages[i].at("role") == "tool") {
1569	                const auto & tool_msg = messages[i];
1570	                std::string name;
1571	                if (tool_msg.contains("tool_call_id") && tool_msg.at("tool_call_id").is_string()) {
1572	                    name = tool_msg.at("tool_call_id");
1573	                } else if (tool_msg.contains("name") && tool_msg.at("name").is_string()) {
1574	                    name = tool_msg.at("name");
1575	                }
1576	                json response;
1577	                if (tool_msg.contains("content")) {
1578	                    const auto & content = tool_msg.at("content");
1579	                    if (content.is_string()) {
1580	                        // Try to parse the content as JSON; fall back to raw string
1581	                        try {
1582	                            response = json::parse(content.get<std::string>());
1583	                        } catch (...) {
1584	                            response = content;
1585	                        }
1586	                    } else {
1587	                        response = content;
1588	                    }
1589	                }
1590	                tool_responses.push_back({{"name", name}, {"response", response}});
1591	                i++;
1592	            }
1593	            result.push_back({{"role", "user"}, {"tool_responses", tool_responses}});
1594	        } else {
1595	            result.push_back(messages[i]);
1596	            i++;
1597	        }
1598	    }
1599	    messages = result;
1600	}
