1094	    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
1095	        // Functionary v3.2 format:
1096	        // - Normal content: >>>all\n{content}
1097	        // - Tool calls: >>>function_name\n{json_args}
1098	        // Generation prompt ends with ">>>" so model outputs recipient immediately
1099	
1100	        // Build content parser for >>>all\n{content}
